define('taoQtiTest/controller/creator/views/testpart',['jquery', 'lodash', 'i18n', 'ui/dialog', 'taoQtiTest/controller/creator/config/defaults', 'taoQtiTest/controller/creator/views/actions', 'taoQtiTest/controller/creator/views/section', 'taoQtiTest/controller/creator/templates/index', 'taoQtiTest/controller/creator/helpers/qtiTest', 'taoQtiTest/controller/creator/helpers/testPartCategory', 'taoQtiTest/controller/creator/helpers/categorySelector', 'taoQtiTest/controller/creator/helpers/translation', 'taoQtiTest/controller/creator/helpers/featureVisibility', 'taoQtiTest/controller/creator/helpers/branchRules'], function ($, _, __, dialog, defaults, actions, sectionView, templates, qtiTestHelper, testPartCategory, categorySelectorFactory, translationHelper, featureVisibility, branchRules) {
  'use strict';
  function setUp(creatorContext, partModel, $testPart) {
    var defaultsConfigs = defaults();
    var $actionContainer = $('h1', $testPart);
    var $titleWithActions = $testPart.children('h1');
    var modelOverseer = creatorContext.getModelOverseer();
    if (!Array.isArray(partModel.branchRules)) {
      partModel.branchRules = [];
    }
    if (!Array.isArray(partModel.preConditions)) {
      partModel.preConditions = [];
    }
    featureVisibility.addTestPartVisibilityProps(partModel);
    actions.properties($actionContainer, 'testpart', partModel, propHandler);
    actions.move($actionContainer, 'testparts', 'testpart');
    sections();
    addSection();
    bindDeleteGuard(creatorContext, partModel, $testPart);
    function propHandler(propView) {
      var $view = propView.getView();
      var mo = modelOverseer;
      var ns = ".branchOptions-".concat(partModel.identifier);
      categoriesProperty($view);
      showBranchRulesUI($view);
      showPreConditionsUI($view);
      mo.off("branch-options-update".concat(ns)).on("branch-options-update".concat(ns), () => {
        showBranchRulesUI($view);
        showPreConditionsUI($view);
      });
      var $identifier = $('[data-bind=identifier]', $titleWithActions);
      $view.on('change.binder', function (e, model) {
        if (e.namespace === 'binder' && model['qti-type'] === 'testPart') {
          $identifier.text(model.identifier);
          modelOverseer.trigger('testpart-change', partModel);
        }
      });
      $testPart.parents('.testparts').on('deleted.deleter', (e, $deletedNode) => {
        if (propView && $deletedNode.attr('id') === $testPart.attr('id')) {
          mo.off("branch-options-update".concat(ns));
          propView.destroy();
        }
      });
      actions.displayCategoryPresets($testPart, 'testpart');
    }
    function addBranchRulesEditorEvents(view) {
      var config = creatorContext.getModelOverseer().getConfig();
      view.off('click', '.branch-rules-add-btn').off('click', '[data-testid="branch-rule-delete"]').off('click', '[data-testid="branch-rule-move-up"]').off('click', '[data-testid="branch-rule-move-down"]').off('change', 'select[name="branch-rules-target"]').off('change', 'select[name="branch-rules-variable"]').off('change', 'select[name="branch-rules-operator"]').off('input', '.branch-rules-value');
      view.on('click', '.branch-rules-add-btn', function () {
        var t = _.get(config, 'branchOptions.targets[0].value', '');
        var v = _.get(config, 'branchOptions.variables[0].value', '');
        partModel.branchRules.push({
          target: t,
          variable: v,
          operator: 'lt',
          value: 0
        });
        renderBranchRules(view);
        modelOverseer.trigger('branch-rules-change');
      });
      view.on('click', '[data-testid="branch-rule-delete"]', e => {
        var i = +$(e.currentTarget).closest('.branch-rules-table-item').data('index');
        if (!Number.isNaN(i)) {
          partModel.branchRules.splice(i, 1);
          renderBranchRules(view);
          modelOverseer.trigger('branch-rules-change');
        }
      });
      view.on('click', '[data-testid="branch-rule-move-up"]', e => {
        if (isDisabled(e.currentTarget)) return;
        var i = +$(e.currentTarget).closest('.branch-rules-table-item').data('index');
        if (i > 0) {
          var [row] = partModel.branchRules.splice(i, 1);
          partModel.branchRules.splice(i - 1, 0, row);
          renderBranchRules(view);
        }
      });
      view.on('click', '[data-testid="branch-rule-move-down"]', e => {
        if (isDisabled(e.currentTarget)) return;
        var i = +$(e.currentTarget).closest('.branch-rules-table-item').data('index');
        if (i < partModel.branchRules.length - 1) {
          var [row] = partModel.branchRules.splice(i, 1);
          partModel.branchRules.splice(i + 1, 0, row);
          renderBranchRules(view);
        }
      });
      view.on('change', 'select[name="branch-rules-target"]', e => {
        var i = +$(e.currentTarget).closest('.branch-rules-table-item').data('index');
        partModel.branchRules[i].target = $(e.currentTarget).val();
      });
      view.on('change', 'select[name="branch-rules-variable"]', e => {
        var i = +$(e.currentTarget).closest('.branch-rules-table-item').data('index');
        partModel.branchRules[i].variable = $(e.currentTarget).val();
      });
      view.on('change', 'select[name="branch-rules-operator"]', e => {
        var i = +$(e.currentTarget).closest('.branch-rules-table-item').data('index');
        partModel.branchRules[i].operator = $(e.currentTarget).val();
      });
      view.on('input', '.branch-rules-value', e => {
        var i = +$(e.currentTarget).closest('.branch-rules-table-item').data('index');
        partModel.branchRules[i].value = $(e.currentTarget).val();
      });
      function isDisabled(el) {
        return $(el).hasClass('disabled') || $(el).attr('aria-disabled') === 'true';
      }
    }
    function addPreConditionsEditorEvents(view) {
      var config = creatorContext.getModelOverseer().getConfig();
      view.off('click', '.precondition-add-btn').off('click', '[data-testid="precondition-delete"]').off('change', 'select[name="precondition-variable"]').off('change', 'select[name="precondition-operator"]').off('input', '.precondition-value');
      view.on('click', '.precondition-add-btn', function () {
        var v = _.get(config, 'branchOptions.variables[0].value', '');
        partModel.preConditions.push({
          variable: v,
          operator: 'lt',
          value: 0
        });
        renderPreConditions(view);
      });
      view.on('click', '[data-testid="precondition-delete"]', e => {
        var i = +$(e.currentTarget).closest('.precondition-table-item').data('index');
        if (!Number.isNaN(i)) {
          partModel.preConditions.splice(i, 1);
          renderPreConditions(view);
        }
      });
      view.on('change', 'select[name="precondition-variable"]', e => {
        var i = +$(e.currentTarget).closest('.precondition-table-item').data('index');
        partModel.preConditions[i].variable = $(e.currentTarget).val();
      });
      view.on('change', 'select[name="precondition-operator"]', e => {
        var i = +$(e.currentTarget).closest('.precondition-table-item').data('index');
        partModel.preConditions[i].operator = $(e.currentTarget).val();
      });
      view.on('input', '.precondition-value', e => {
        var i = +$(e.currentTarget).closest('.precondition-table-item').data('index');
        partModel.preConditions[i].value = $(e.currentTarget).val();
      });
    }
    function initializeSelect2Dropdowns($selects, dropdownCssClass) {
      $selects.each(function () {
        var $select = $(this);
        $select.select2({
          minimumResultsForSearch: -1,
          width: '100%',
          dropdownCssClass: dropdownCssClass
        });
        $select.on('select2-open', function (e) {
          var $dropdown = $('.select2-drop.' + dropdownCssClass);
          if ($dropdown.length) {
            var $parent = $select.parent();
            var $container = $parent.find('.select2-container');
            $dropdown.css({
              'width': 'auto',
              'max-width': '258px',
              'min-width': "".concat($container.width(), "px"),
              'font-size': '1rem'
            });
            var containerOffset = $container.offset();
            var dropdownHeight = $('#select2-drop').height();
            $dropdown.css({
              'left': containerOffset.left + 'px',
              'top': containerOffset.top - dropdownHeight - 3 + 'px'
            });
          }
        });
      });
    }
    function renderBranchRules(view) {
      var cfg = creatorContext.getModelOverseer().getConfig();
      var options = cfg && cfg.branchOptions || {
        targets: [],
        variables: [],
        operators: []
      };
      var html = templates.branchRules({
        branchRules: partModel.branchRules,
        branchOptions: options
      });
      var $tbody = $('.testpart-branch-rules', view);
      $tbody.find('select.select2').each(function () {
        if ($(this).data('select2')) $(this).select2('destroy');
      });
      $tbody.html(html);
      initializeSelect2Dropdowns($tbody.find('select.select2'), 'branch-rules-dropdown');
    }
    function renderPreConditions(view) {
      var cfg = creatorContext.getModelOverseer().getConfig();
      var options = cfg && cfg.branchOptions || {
        targets: [],
        variables: [],
        operators: []
      };
      var html = templates.preConditions({
        preConditions: partModel.preConditions,
        branchOptions: options
      });
      var $tbody = $('.testpart-preconditions', view);
      $tbody.find('select.select2').each(function () {
        if ($(this).data('select2')) $(this).select2('destroy');
      });
      $tbody.html(html);
      initializeSelect2Dropdowns($tbody.find('select.select2'), 'preconditions-dropdown');
    }
    function showBranchRulesUI(view) {
      var $container = $('.testpart-branch-rules', view);
      $container.find('.unsupported-qti-message').remove();
      if (hasUnsupportedBranchRules(partModel)) {
        renderUnsupportedMessage($container);
      } else {
        renderBranchRules(view);
        addBranchRulesEditorEvents(view);
      }
    }
    function showPreConditionsUI(view) {
      var $container = $('.testpart-preconditions', view);
      $container.find('.unsupported-qti-message').remove();
      if (hasUnsupportedPreConditions(partModel)) {
        renderUnsupportedMessage($container);
      } else {
        renderPreConditions(view);
        addPreConditionsEditorEvents(view);
      }
    }
    function sections() {
      if (!partModel.assessmentSections) {
        partModel.assessmentSections = [];
      }
      $('.section', $testPart).each(function () {
        var $section = $(this);
        var index = $section.data('bind-index');
        if (!partModel.assessmentSections[index]) {
          partModel.assessmentSections[index] = {};
        }
        sectionView.setUp(creatorContext, partModel.assessmentSections[index], partModel, $section);
      });
    }
    function addSection() {
      $('.section-adder', $testPart).adder({
        target: $('.sections', $testPart),
        content: templates.section,
        templateData: function templateData(cb) {
          cb({
            'qti-type': 'assessmentSection',
            identifier: qtiTestHelper.getAvailableIdentifier(modelOverseer.getModel(), 'assessmentSection', defaultsConfigs.sectionIdPrefix),
            title: defaultsConfigs.sectionTitlePrefix,
            index: 0,
            sectionParts: [],
            visible: true,
            itemSessionControl: {
              maxAttempts: defaultsConfigs.maxAttempts
            }
          });
        }
      });
      $(document).off('add.binder', "[id=".concat($testPart.attr('id'), "] .sections")).on('add.binder', "[id=".concat($testPart.attr('id'), "] .sections"), function (e, $section) {
        if (e.namespace === 'binder' && $section.hasClass('section')) {
          var index = $section.data('bind-index');
          var sectionModel = partModel.assessmentSections[index];
          var config = modelOverseer.getConfig();
          if (partModel.translation) {
            var originIdentifiers = translationHelper.registerModelIdentifiers(config.originModel);
            var originSection = originIdentifiers[sectionModel.identifier];
            translationHelper.setTranslationFromOrigin(sectionModel, originSection);
          }
          sectionView.setUp(creatorContext, sectionModel, partModel, $section);
          modelOverseer.trigger('section-add', sectionModel);
        }
      });
    }
    function categoriesProperty($view) {
      var categoriesSummary = testPartCategory.getCategories(partModel);
      var categorySelector = categorySelectorFactory($view);
      categorySelector.createForm(categoriesSummary.all, 'testPart');
      updateFormState(categorySelector);
      $view.on('propopen.propview', function () {
        updateFormState(categorySelector);
      });
      $view.on('set-default-categories', function () {
        partModel.categories = defaultsConfigs.categories;
        updateFormState(categorySelector);
      });
      categorySelector.on('category-change', function (selected, indeterminate) {
        testPartCategory.setCategories(partModel, selected, indeterminate);
        creatorContext.getModelOverseer().trigger('category-change');
      });
    }
    function updateFormState(categorySelector) {
      var categoriesSummary = testPartCategory.getCategories(partModel);
      categorySelector.updateFormState(categoriesSummary.propagated, categoriesSummary.partial);
    }
  }
  function hasUnsupportedBranchRules(partModel) {
    return (partModel.branchRules || []).some(r => r && r.__unsupported);
  }
  function hasUnsupportedPreConditions(partModel) {
    return (partModel.preConditions || []).some(r => r && r.__unsupported);
  }
  function renderUnsupportedMessage($container) {
    var bannerHtml = "<div class=\"banner banner-danger unsupported-qti-message\" role=\"alert\" aria-live=\"assertive\" aria-atomic=\"true\">\n                <span class=\"banner-icon icon-danger\" aria-hidden=\"true\"></span>\n                <div>\n                    ".concat(__('The QTI syntax used for this test is not yet supported by the current UI. To effectively review or edit your content, we recommend using the XML Editor functionality for a seamless experience.'), "\n                </div>\n            </div>");
    $container.html(bannerHtml);
  }
  function bindDeleteGuard(creatorContext, partModel, $testPart) {
    var modelOverseer = creatorContext.getModelOverseer();
    var $deleteBtn = $testPart.find('[data-testid="remove-test-part"]');
    var suppressGuard = false;
    var ns = '.guard';
    $deleteBtn.off(ns).on("click".concat(ns), function (e) {
      if (suppressGuard) return;
      e.preventDefault();
      e.stopImmediatePropagation();
      var model = modelOverseer.getModel();
      var partId = partModel.identifier;
      var refs = branchRules.collectBranchRuleRefsByTarget(model, partId);
      if (refs.count === 0) {
        suppressGuard = true;
        $deleteBtn.trigger('click');
        suppressGuard = false;
        return;
      }
      var msg = "\n                ".concat(__('This test part is used as a target in %s path(s).', refs.count), "<br/><br/>\n                ").concat(__('If you continue, those paths will be removed.'), "\n            ");
      dialog({
        message: msg,
        buttons: [{
          id: 'cancel',
          type: 'regular',
          label: __('Cancel'),
          close: true
        }, {
          id: 'remove',
          type: 'info',
          label: __('Remove'),
          close: true
        }],
        autoRender: true,
        autoDestroy: true,
        onRemoveBtn: () => {
          branchRules.purgeRulesWithMissingTargets(model, partId);
          branchRules.refreshOptions(modelOverseer);
          suppressGuard = true;
          $deleteBtn.trigger('click');
          suppressGuard = false;
        }
      });
    });
    $testPart.parents('.testparts').off("deleted.deleter".concat(ns)).on("deleted.deleter".concat(ns), (e, $deletedNode) => {
      if ($deletedNode.attr('id') === $testPart.attr('id')) {
        $deleteBtn.off(ns);
        $(e.currentTarget).off("deleted.deleter".concat(ns));
      }
    });
  }
  function listenActionState() {
    var $testParts = $('.testpart');
    actions.removable($testParts, 'h1');
    actions.movable($testParts, 'testpart', 'h1');
    $('.testparts').on('delete', function (e) {
      var $target = $(e.target);
      if ($target.hasClass('testpart')) {
        actions.disable($(e.target.id), 'h1');
      }
    }).on('add change undo.deleter deleted.deleter', function (e) {
      var $target = $(e.target);
      if ($target.hasClass('testpart') || $target.hasClass('testparts')) {
        $testParts = $('.testpart');
        actions.removable($testParts, 'h1');
        actions.movable($testParts, 'testpart', 'h1');
      }
    });
  }
  return {
    setUp: setUp,
    listenActionState: listenActionState
  };
});
