define('taoQtiTest/controller/creator/helpers/ruleExpressionHelper',[], function () {
  'use strict';
  function isUiCompatibleExpression(expr) {
    if (!expr) return false;
    var supported = ['lt', 'lte', 'equal', 'gt', 'gte'];
    if (!supported.includes(expr['qti-type'])) return false;
    var parts = Array.isArray(expr.expressions) ? expr.expressions : [];
    if (parts.length !== 2) return false;
    var hasVariable = parts.some(p => p && p['qti-type'] === 'variable' && p.identifier);
    var hasBaseValue = parts.some(p => p && p['qti-type'] === 'baseValue');
    return hasVariable && hasBaseValue;
  }
  return {
    isUiCompatibleExpression
  };
});
