define('taoQtiTest/provider/testItems',['lodash', 'i18n', 'util/url', 'core/dataProvider/request'], function (_, __, urlUtil, request) {
  'use strict';
  var defaultConfig = {
    getItemClasses: {
      url: urlUtil.route('getItemClasses', 'Items', 'taoQtiTest')
    },
    getItemClassChildren: {
      url: urlUtil.route('getItemClassChildren', 'Items', 'taoQtiTest')
    },
    getItems: {
      url: urlUtil.route('getItems', 'Items', 'taoQtiTest')
    },
    getItemClassProperties: {
      url: urlUtil.route('create', 'RestFormItem', 'taoItems')
    }
  };
  return function testItemProviderFactory(config) {
    config = _.defaults(config || {}, defaultConfig);
    return {
      getItemClasses: function getItemClasses() {
        return request(config.getItemClasses.url);
      },
      getItemClassChildren: function getItemClassChildren(classUri) {
        return request(config.getItemClassChildren.url, {
          classUri: classUri
        });
      },
      getItems: function getItems(params) {
        return request(config.getItems.url, params);
      },
      getItemClassProperties: function getItemClassProperties(classUri) {
        return request(config.getItemClassProperties.url, {
          classUri: classUri
        });
      }
    };
  };
});
