define('taoQtiTest/controller/creator/views/property',['jquery', 'uikitLoader', 'core/databinder', 'taoQtiTest/controller/creator/templates/index'], function ($, ui, DataBinder, templates) {
  'use strict';
  var propView = function propView(tmplName, model) {
    var $container = $('.test-creator-props');
    var template = templates.properties[tmplName];
    var $view;
    var open = function propOpen() {
      var binderOptions = {
        templates: templates.properties
      };
      $container.children('.props').hide().trigger('propclose.propview');
      $view = $(template(model)).appendTo($container).filter('.props');
      ui.startDomComponent($view);
      var databinder = new DataBinder($view, model, binderOptions);
      databinder.bind();
      propValidation();
      $view.trigger('propopen.propview');
      var $identifier = $view.find("[id=\"props-".concat(model.identifier, "\"]"));
      $view.on('change.binder', function (e) {
        if (e.namespace === 'binder' && $identifier.length) {
          $identifier.text(model.identifier);
        }
      });
    };
    var getView = function propGetView() {
      return $view;
    };
    var isOpen = function propIsOpen() {
      return $view.css('display') !== 'none';
    };
    var onOpen = function propOnOpen(cb) {
      $view.on('propopen.propview', function (e) {
        e.stopPropagation();
        cb();
      });
    };
    var onClose = function propOnClose(cb) {
      $view.on('propclose.propview', function (e) {
        e.stopPropagation();
        cb();
      });
    };
    var destroy = function propDestroy() {
      $view.remove();
    };
    var toggle = function propToggle() {
      $container.children('.props').not($view).hide().trigger('propclose.propview');
      if (isOpen()) {
        $view.hide().trigger('propclose.propview');
      } else {
        $view.show().trigger('propopen.propview');
      }
    };
    function propValidation() {
      $view.on('validated.group', function (e, isValid) {
        var warningIconSelector = 'span.configuration-issue';
        var $test = $('.tlb-button-on').parents('.test-creator-test');
        var errors = $(e.currentTarget).find('span.validate-error');
        var currentTargetId = $(e.currentTarget).find('span[data-bind="identifier"]').attr('id');
        var currentTargetIdSelector = "[id=\"".concat(currentTargetId && currentTargetId.slice(6), "\"]");
        if (e.namespace === 'group') {
          if (isValid && errors.length === 0) {
            if ($(e.currentTarget).hasClass('test-props')) {
              $test.find(warningIconSelector).first().css('display', 'none');
            }
            if (currentTargetId) {
              $(currentTargetIdSelector).find(warningIconSelector).first().css('display', 'none');
            }
          } else {
            if ($(e.currentTarget).hasClass('test-props')) {
              $test.find(warningIconSelector).first().css('display', 'inline');
            }
            if (currentTargetId) {
              $(currentTargetIdSelector).find(warningIconSelector).first().css('display', 'inline');
            }
          }
        }
      });
      $view.groupValidator({
        events: ['keyup', 'change', 'blur']
      });
    }
    return {
      open: open,
      getView: getView,
      isOpen: isOpen,
      onOpen: onOpen,
      onClose: onClose,
      destroy: destroy,
      toggle: toggle
    };
  };
  return propView;
});
